.darma-loader-darma-custom-075 {
  display: inline-grid;
  width: 80px;
  aspect-ratio: 2;
  box-shadow: 0 5px #574951;
  overflow: hidden;
}
.darma-loader-darma-custom-075:before {
  content: "";
  margin: 0 25%;
  background: #83988E;
  clip-path: polygon(97.55% 65.45%,50% 100%,2.45% 65.45%,20.61% 9.55%,79.39% 9.55%);
  transform-origin: bottom;
  animation: 
    darma-loader-darma-custom-075-l7-0 .5s linear infinite,
    darma-loader-darma-custom-075-l7-1  3s steps(6) infinite;
}
@keyframes darma-loader-darma-custom-075-l7-0 {
  0%{rotate: -36deg}
  to{rotate:  36deg}
}
@keyframes darma-loader-darma-custom-075-l7-1 {
  0%{translate: -174% 0}
  to{translate:  174% 0}
}

